import { GoogleGenAI, Type, Modality } from "@google/genai";
import { ContentEmpireOutput } from "../types";

const API_KEY = process.env.API_KEY || "";

export const getGeminiClient = () => {
  if (!API_KEY) throw new Error("Missing Gemini API Key");
  return new GoogleGenAI({ apiKey: API_KEY });
};

export async function transcribeAudio(base64Audio: string): Promise<string> {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          { inlineData: { mimeType: 'audio/webm', data: base64Audio } },
          { text: "Транскрибируй это аудио точно. Аудио может быть на русском или таджикском языке. Выведи только текст, без комментариев." }
        ]
      }
    ]
  });
  return response.text || "Ошибка транскрипции.";
}

export async function generateContentEmpire(transcription: string): Promise<ContentEmpireOutput> {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `На основе следующей транскрипции голосовой заметки: "${transcription}", создай пакет контента для личного бренда профессионального бизнес-спикера. 
    Ввод может быть на русском или таджикском языке. Вывод (контент) должен быть на русском языке.

    Особое внимание удели:
    1. Режиссуре видео (Video Director): Распиши посекундный план с визуальными эффектами.
    2. Лид-магниту (Money Maker): Создай структуру полезного PDF-файла или чек-листа, который можно подарить за комментарий.

    Выведи результат строго в формате JSON.

    Формат:
    {
      "videoDirectorPlan": {
        "hook": "Сильный зацеп",
        "timeline": [
          {"timestamp": "00:00-00:05", "visual": "Крупный план, взгляд в камеру", "speech": "Текст речи", "textOverlay": "Текст на экране"},
          {"timestamp": "00:05-00:15", "visual": "Смена локации, движение", "speech": "Текст речи", "textOverlay": "Ключевые слова"}
        ],
        "finalCta": "Призыв к действию"
      },
      "instagramPost": {
        "caption": "Увлекательная подпись",
        "hashtags": ["#тег1"]
      },
      "linkedInArticle": {
        "title": "Заголовок",
        "content": "Текст статьи"
      },
      "leadMagnet": {
        "title": "Название гайда/чек-листа",
        "description": "Краткое описание пользы",
        "points": ["Пункт 1", "Пункт 2"],
        "ctaTrigger": "Слово-триггер для Директа (например, 'ГЕЙМПЛЕЙ')"
      },
      "storyIdeas": ["Идея 1", "Идея 2", "Идея 3"]
    }`,
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 15000 },
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          videoDirectorPlan: {
            type: Type.OBJECT,
            properties: {
              hook: { type: Type.STRING },
              timeline: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    timestamp: { type: Type.STRING },
                    visual: { type: Type.STRING },
                    speech: { type: Type.STRING },
                    textOverlay: { type: Type.STRING }
                  },
                  required: ['timestamp', 'visual', 'speech', 'textOverlay']
                }
              },
              finalCta: { type: Type.STRING }
            },
            required: ['hook', 'timeline', 'finalCta']
          },
          instagramPost: {
            type: Type.OBJECT,
            properties: {
              caption: { type: Type.STRING },
              hashtags: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ['caption', 'hashtags']
          },
          linkedInArticle: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              content: { type: Type.STRING }
            },
            required: ['title', 'content']
          },
          leadMagnet: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              description: { type: Type.STRING },
              points: { type: Type.ARRAY, items: { type: Type.STRING } },
              ctaTrigger: { type: Type.STRING }
            },
            required: ['title', 'description', 'points', 'ctaTrigger']
          },
          storyIdeas: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ['videoDirectorPlan', 'instagramPost', 'linkedInArticle', 'leadMagnet', 'storyIdeas']
      }
    }
  });

  return JSON.parse(response.text || "{}");
}

export async function speakText(text: string): Promise<string> {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Прочитай этот контент профессионально и четко: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' },
        },
      },
    },
  });
  return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || "";
}

import React, { useState } from 'react';
import { Copy, Check, Loader2, Volume2, Clapperboard, Monitor, User } from 'lucide-react';
import { speakText } from '../services/geminiService';
import { decode, decodeAudioData } from '../utils/audioUtils';
import { VideoFrame } from '../types';

interface ContentCardProps {
  title: string;
  icon: React.ReactNode;
  content?: string;
  subContent?: string[];
  timeline?: VideoFrame[];
  leadMagnetFooter?: string;
  accentColor?: string;
}

const ContentCard: React.FC<ContentCardProps> = ({ title, icon, content, subContent, timeline, leadMagnetFooter, accentColor = "amber" }) => {
  const [copied, setCopied] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);

  const handleCopy = () => {
    const textToCopy = timeline 
      ? timeline.map(f => `[${f.timestamp}] ${f.visual}\nРечь: ${f.speech}\nТекст: ${f.textOverlay}`).join('\n\n')
      : content || (subContent ? subContent.join('\n') : "");

    navigator.clipboard.writeText(textToCopy);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleSpeak = async () => {
    if (isSpeaking) return;
    setIsSpeaking(true);
    try {
      const textToSpeak = timeline 
        ? timeline.map(f => f.speech).join(' ') 
        : content || "";
      const base64Audio = await speakText(textToSpeak);
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const buffer = await decodeAudioData(decode(base64Audio), audioCtx, 24000, 1);
      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.onended = () => setIsSpeaking(false);
      source.start();
    } catch (error) {
      console.error("Ошибка озвучки:", error);
      setIsSpeaking(false);
    }
  };

  const accentClass = accentColor === "red" ? "text-red-500 bg-red-500/10" : "text-amber-500 bg-amber-500/10";
  const borderClass = accentColor === "red" ? "hover:border-red-500/30" : "hover:border-amber-500/30";

  return (
    <div className={`glass-card rounded-2xl p-6 transition-all ${borderClass}`}>
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-3">
          <div className={`p-2 rounded-lg ${accentClass}`}>
            {icon}
          </div>
          <h3 className="font-bold text-lg text-white">{title}</h3>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleSpeak}
            disabled={isSpeaking}
            className="p-2 hover:bg-white/5 rounded-full transition-colors text-zinc-400 hover:text-amber-500"
          >
            {isSpeaking ? <Loader2 size={18} className="animate-spin" /> : <Volume2 size={18} />}
          </button>
          <button 
            onClick={handleCopy}
            className="p-2 hover:bg-white/5 rounded-full transition-colors text-zinc-400 hover:text-white"
          >
            {copied ? <Check size={18} className="text-green-500" /> : <Copy size={18} />}
          </button>
        </div>
      </div>

      <div className="space-y-4">
        {content && (
          <p className="text-zinc-300 leading-relaxed whitespace-pre-wrap">
            {content}
          </p>
        )}

        {timeline && (
          <div className="space-y-6">
            {timeline.map((frame, i) => (
              <div key={i} className="relative pl-6 border-l-2 border-white/10 pb-2">
                <div className={`absolute -left-[5px] top-1 w-2 h-2 rounded-full ${accentColor === 'red' ? 'bg-red-500' : 'bg-amber-500'}`}></div>
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-[10px] font-mono font-bold bg-white/10 text-zinc-400 px-1.5 py-0.5 rounded">{frame.timestamp}</span>
                </div>
                <div className="space-y-2">
                  <div className="flex gap-2 text-xs text-zinc-400 italic">
                    <User size={12} className="mt-0.5 flex-shrink-0" />
                    <span>{frame.visual}</span>
                  </div>
                  <div className="text-sm text-zinc-200 bg-white/5 p-3 rounded-lg border border-white/5">
                    "{frame.speech}"
                  </div>
                  <div className="flex gap-2 text-xs font-semibold text-amber-500/80 items-center">
                    <Monitor size={12} />
                    <span>Overlay: {frame.textOverlay}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {subContent && subContent.length > 0 && (
          <div className="pt-4 border-t border-white/5">
            <h4 className="text-xs font-semibold text-zinc-500 uppercase tracking-wider mb-2">Детали</h4>
            <ul className="space-y-2">
              {subContent.map((item, i) => (
                <li key={i} className="flex gap-2 text-sm text-zinc-400">
                  <span className={`flex-shrink-0 mt-1.5 w-1 h-1 rounded-full ${accentColor === 'red' ? 'bg-red-500/50' : 'bg-amber-500/50'}`}></span>
                  {item}
                </li>
              ))}
            </ul>
          </div>
        )}

        {leadMagnetFooter && (
          <div className="mt-6 p-4 bg-gradient-to-br from-amber-500/20 to-red-500/20 rounded-xl border border-white/10 text-center">
            <p className="text-xs text-zinc-400 mb-2 uppercase font-bold tracking-widest">Призыв для сбора лидов</p>
            <p className="text-sm font-bold text-white">
              Пиши слово <span className="text-amber-500">"{leadMagnetFooter}"</span> в комментариях, чтобы получить этот материал!
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

export default ContentCard;

import React, { useState, useRef } from 'react';
import { 
  Mic, 
  Square, 
  Sparkles, 
  Video, 
  Instagram, 
  Linkedin, 
  LayoutGrid, 
  BrainCircuit,
  Loader2,
  AlertCircle,
  Clapperboard,
  FileText,
  DollarSign
} from 'lucide-react';
import { AppTab, ContentEmpireOutput } from './types';
import { transcribeAudio, generateContentEmpire } from './services/geminiService';
import { blobToBase64 } from './utils/audioUtils';
import ContentCard from './components/ContentCard';
import LiveStrategist from './components/LiveStrategist';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.FACTORY);
  const [isRecording, setIsRecording] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<ContentEmpireOutput | null>(null);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      mediaRecorderRef.current = recorder;
      chunksRef.current = [];

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      recorder.onstop = async () => {
        const audioBlob = new Blob(chunksRef.current, { type: 'audio/webm' });
        processAudio(audioBlob);
      };

      recorder.start();
      setIsRecording(true);
      setError(null);
    } catch (err) {
      setError("Пожалуйста, разрешите доступ к микрофону для записи идей.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
    }
  };

  const processAudio = async (blob: Blob) => {
    setIsProcessing(true);
    try {
      const base64 = await blobToBase64(blob);
      const transcription = await transcribeAudio(base64);
      const content = await generateContentEmpire(transcription);
      setResults(content);
    } catch (err: any) {
      setError(err.message || "Не удалось обработать аудио. Попробуйте еще раз.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="min-h-screen pb-20">
      {/* Навигация */}
      <nav className="sticky top-0 z-50 glass-card border-b border-white/5 px-6 py-4 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="w-10 h-10 bg-gradient-to-br from-amber-500 to-red-500 rounded-xl flex items-center justify-center text-zinc-900 shadow-lg shadow-amber-500/20">
            <Sparkles size={24} strokeWidth={2.5} />
          </div>
          <span className="text-xl font-bold tracking-tight uppercase">ФАБРИКА <span className="gradient-text">БРЕНДА</span></span>
        </div>

        <div className="flex bg-white/5 rounded-full p-1 border border-white/10">
          <button 
            onClick={() => setActiveTab(AppTab.FACTORY)}
            className={`flex items-center gap-2 px-6 py-2 rounded-full text-sm font-medium transition-all ${activeTab === AppTab.FACTORY ? 'bg-amber-500 text-zinc-900 shadow-md' : 'text-zinc-400 hover:text-white'}`}
          >
            <LayoutGrid size={18} />
            Фабрика
          </button>
          <button 
            onClick={() => setActiveTab(AppTab.STRATEGIST)}
            className={`flex items-center gap-2 px-6 py-2 rounded-full text-sm font-medium transition-all ${activeTab === AppTab.STRATEGIST ? 'bg-amber-500 text-zinc-900 shadow-md' : 'text-zinc-400 hover:text-white'}`}
          >
            <BrainCircuit size={18} />
            Стратег
          </button>
        </div>
      </nav>

      {/* Контент */}
      <main className="container mx-auto max-w-6xl mt-8">
        {activeTab === AppTab.FACTORY && (
          <div className="px-4 space-y-12">
            {/* Секция записи */}
            <div className="text-center py-12">
              <h1 className="text-5xl font-black mb-4 tracking-tight leading-tight">Ваш контент на <br/><span className="gradient-text">автопилоте</span></h1>
              <p className="text-zinc-400 text-lg mb-10 max-w-2xl mx-auto">Расскажите свою идею. Мы превратим её в профессиональный сценарий, пост и готовый лид-магнит.</p>

              <div className="flex flex-col items-center gap-6">
                <button
                  onClick={isRecording ? stopRecording : startRecording}
                  disabled={isProcessing}
                  className={`w-28 h-28 rounded-full flex items-center justify-center transition-all duration-300 transform active:scale-95 shadow-2xl ${
                    isRecording 
                    ? 'bg-red-500 animate-pulse ring-8 ring-red-500/20' 
                    : 'bg-amber-500 hover:bg-amber-600 glow-button'
                  }`}
                >
                  {isRecording ? <Square size={36} fill="white" stroke="white" /> : <Mic size={36} className="text-zinc-900" strokeWidth={2.5} />}
                </button>

                <div className="flex flex-col items-center">
                  <span className={`text-sm font-bold tracking-widest uppercase transition-colors ${isRecording ? 'text-red-500' : 'text-zinc-500'}`}>
                    {isRecording ? "Слушаю вашу мысль..." : isProcessing ? "Создаю контент-империю..." : "Нажмите, чтобы начать"}
                  </span>
                </div>
              </div>
            </div>

            {error && (
              <div className="flex items-center gap-3 bg-red-500/10 border border-red-500/20 p-4 rounded-xl text-red-500 max-w-md mx-auto mb-8">
                <AlertCircle size={20} />
                <p className="text-sm font-medium">{error}</p>
              </div>
            )}

            {isProcessing && (
              <div className="flex flex-col items-center justify-center gap-4 py-20">
                <Loader2 size={48} className="text-amber-500 animate-spin" />
                <p className="text-zinc-400 animate-pulse font-medium text-center">
                  AI-Режиссер монтирует план...<br/>
                  Стратег пакует лид-магнит...
                </p>
              </div>
            )}

            {results && !isProcessing && (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pb-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="md:col-span-2">
                  <ContentCard 
                    title="AI Видео-Режиссер (Reels Script)" 
                    icon={<Clapperboard size={20} />} 
                    accentColor="red"
                    content={`Hook: ${results.videoDirectorPlan.hook}\n\nCall to Action: ${results.videoDirectorPlan.finalCta}`}
                    timeline={results.videoDirectorPlan.timeline}
                  />
                </div>

                <ContentCard 
                  title="Lead Magnet (Money Maker)" 
                  icon={<DollarSign size={20} />} 
                  content={`Тема: ${results.leadMagnet.title}\n\n${results.leadMagnet.description}`}
                  subContent={results.leadMagnet.points}
                  leadMagnetFooter={results.leadMagnet.ctaTrigger}
                />

                <ContentCard 
                  title="Instagram Post" 
                  icon={<Instagram size={20} />} 
                  content={results.instagramPost.caption}
                  subContent={results.instagramPost.hashtags}
                />

                <ContentCard 
                  title="LinkedIn Article" 
                  icon={<Linkedin size={20} />} 
                  content={`${results.linkedInArticle.title}\n\n${results.linkedInArticle.content}`}
                />

                <div className="md:col-span-2">
                  <ContentCard 
                    title="Stories Strategy (5 Days)" 
                    icon={<Sparkles size={20} />} 
                    content="План ежедневного прогрева аудитории:"
                    subContent={results.storyIdeas}
                  />
                </div>
              </div>
            )}
          </div>
        )}

        {activeTab === AppTab.STRATEGIST && (
          <LiveStrategist />
        )}
      </main>

      {/* Футер */}
      <footer className="fixed bottom-0 left-0 right-0 glass-card py-3 px-8 border-t border-white/5 hidden md:flex items-center justify-between text-xs text-zinc-500 uppercase tracking-widest font-bold">
        <div className="flex gap-8">
          <div className="flex items-center gap-2"><span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span> Gemini 3 Pro AI</div>
          <div>Mode: Director & Money Maker Enabled</div>
        </div>
        <div className="flex gap-4">
          <span>v3.0 Контент Фабрика</span>
          <span className="text-amber-500/80">Бизнес Доступ</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

