export async function speakText(text: string): Promise<string> {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Прочитай этот контент профессионально и четко: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' },
        },
      },
    },
  });
  return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || "";
}

export async function generateSalesFeedback(transcript: string): Promise<SalesFeedback> {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Проанализируй следующий диалог продажи:
    ---
    ${transcript}
    ---
    Выдай объективную оценку по 5-балльной шкале, выдели 3 сильных стороны, 3 слабых стороны и дай конкретный совет по улучшению.
    Отвечай строго в формате JSON.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          score: { type: Type.NUMBER },
          strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
          weaknesses: { type: Type.ARRAY, items: { type: Type.STRING } },
          tips: { type: Type.STRING }
        },
        required: ['score', 'strengths', 'weaknesses', 'tips']
      }
    }
  });
  return JSON.parse(response.text || "{}");
}

