const SalesDojo: React.FC = () => {
  const [selectedPersona, setSelectedPersona] = useState<SalesPersona | null>(null);
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [feedback, setFeedback] = useState<SalesFeedback | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [transcript, setTranscript] = useState<string>("");

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const startTraining = async (persona: SalesPersona) => {
    setFeedback(null);
    setTranscript("");
    setIsConnecting(true);
    setSelectedPersona(persona);

    try {
      const ai = getGeminiClient();
      streamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true });

      audioContextRef.current = new AudioContext({ sampleRate: 16000 });
      outputAudioContextRef.current = new AudioContext({ sampleRate: 24000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsActive(true);
            setIsConnecting(false);
            const source = audioContextRef.current!.createMediaStreamSource(streamRef.current!);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };

              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              const ctx = outputAudioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }

            // Capture transcription for feedback
            if (message.serverContent?.outputTranscription) {
              setTranscript(prev => prev + "\nКлиент: " + message.serverContent?.outputTranscription?.text);
            }
            if (message.serverContent?.inputTranscription) {
              setTranscript(prev => prev + "\nПродавец: " + message.serverContent?.inputTranscription?.text);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => console.error("Dojo Error:", e),
          onclose: () => setIsActive(false),
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: persona.instruction,
          outputAudioTranscription: {},
          inputAudioTranscription: {},
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: persona.id === 'exec' ? 'Puck' : 'Fenrir' } } }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      setIsConnecting(false);
    }
  };

  const stopTraining = async () => {
    if (sessionRef.current) sessionRef.current.close();
    if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    setIsActive(false);

    // Analyze session
    if (transcript.length > 20) {
      setIsAnalyzing(true);
      try {
        const report = await generateSalesFeedback(transcript);
        setFeedback(report);
      } catch (err) {
        console.error("Feedback analysis failed", err);
      } finally {
        setIsAnalyzing(false);
      }
    }
  };

  const renderIcon = (id: string) => {
    switch (id) {
      case 'skeptic': return <UserX size={24} />;
      case 'exec': return <Award size={24} />;
      case 'anxious': return <ShieldCheck size={24} />;
      default: return <Target size={24} />;
    }
  };

  return (
    <div className="max-w-5xl mx-auto px-4 py-8">
      {!isActive && !feedback && !isAnalyzing && (
        <div className="space-y-12 text-center">
          <div>
            <h1 className="text-5xl font-black mb-4 tracking-tighter">SALES <span className="gradient-text">DOJO</span></h1>
            <p className="text-zinc-400 text-lg max-w-xl mx-auto">Выберите противника и отработайте возражения в реальном времени. Это безопасное место для ваших ошибок.</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {PERSONAS.map(p => (
              <button
                key={p.id}
                onClick={() => startTraining(p)}
                disabled={isConnecting}
                className="glass-card p-8 rounded-3xl text-left hover:border-amber-500/50 transition-all group relative overflow-hidden"
              >
                <div className="p-4 bg-white/5 rounded-2xl w-fit mb-6 text-amber-500 group-hover:scale-110 transition-transform">
                  {renderIcon(p.id)}
                </div>
                <h3 className="text-xl font-bold mb-2 text-white">{p.name}</h3>
                <p className="text-sm text-zinc-400 leading-relaxed">{p.description}</p>
                <div className="mt-6 flex items-center gap-2 text-xs font-bold text-amber-500/0 group-hover:text-amber-500 transition-all">
                  НАЧАТЬ БОЙ <ChevronRight size={14} />
                </div>
              </button>
            ))}
          </div>
        </div>
      )}

      {isActive && (
        <div className="glass-card rounded-[40px] p-12 text-center relative border-amber-500/30 shadow-2xl shadow-amber-500/10">
          <div className="absolute top-8 right-8 flex items-center gap-2 text-red-500 font-mono text-sm animate-pulse">
            <div className="w-2 h-2 bg-red-500 rounded-full"></div> REC LIVE
          </div>

          <div className="flex flex-col items-center gap-8">
            <div className="relative">
              <div className="w-32 h-32 rounded-full bg-amber-500/10 flex items-center justify-center text-amber-500">
                <Mic size={48} className="animate-pulse" />
              </div>
              <div className="absolute inset-0 rounded-full border-4 border-amber-500/20 animate-ping"></div>
            </div>

            <div>
              <span className="text-xs font-bold tracking-widest text-zinc-500 uppercase">Оппонент</span>
              <h2 className="text-3xl font-black text-white mt-1 uppercase">{selectedPersona?.name}</h2>
            </div>

            <div className="w-full max-w-md h-12 flex items-center justify-center gap-1">
              {[...Array(12)].map((_, i) => (
                <div 
                  key={i} 
                  className="w-1.5 bg-amber-500 rounded-full transition-all duration-75"
                  style={{ height: `${Math.random() * 100}%`, opacity: 0.3 + (Math.random() * 0.7) }}
                ></div>
              ))}
            </div>

            <button
              onClick={stopTraining}
