            >
              <MicOff size={20} /> ЗАВЕРШИТЬ И ПОЛУЧИТЬ ОЦЕНКУ
            </button>
          </div>
        </div>
      )}

      {isAnalyzing && (
        <div className="py-20 text-center flex flex-col items-center gap-6">
          <div className="relative">
            <Loader2 size={64} className="text-amber-500 animate-spin" />
            <BrainCircuit size={24} className="absolute inset-0 m-auto text-white" />
          </div>
          <div className="space-y-2">
            <h3 className="text-2xl font-bold">Анализируем ваш бой...</h3>
            <p className="text-zinc-500">ИИ-тренер изучает ваши аргументы и работу с возражениями.</p>
          </div>
        </div>
      )}

      {feedback && (
        <div className="animate-in fade-in slide-in-from-bottom-8 duration-500 space-y-8 pb-20">
          <div className="flex items-end justify-between">
            <div>
              <span className="text-xs font-bold text-amber-500 uppercase tracking-widest">Результаты тренировки</span>
              <h2 className="text-4xl font-black text-white mt-2">ОТЧЕТ ТРЕНЕРА</h2>
            </div>
            <div className="text-right">
              <div className="text-5xl font-black text-amber-500">{feedback.score}<span className="text-xl text-zinc-600">/5</span></div>
              <div className="text-xs font-bold text-zinc-500 uppercase">Итоговый балл</div>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="glass-card p-8 rounded-3xl border-green-500/20">
              <div className="flex items-center gap-3 text-green-500 mb-6">
                <TrendingUp size={20} />
                <h3 className="font-bold uppercase tracking-tight">Сильные стороны</h3>
              </div>
              <ul className="space-y-4">
                {feedback.strengths.map((s, i) => (
                  <li key={i} className="flex gap-3 text-sm text-zinc-300">
                    <span className="text-green-500 font-bold">+</span> {s}
                  </li>
                ))}
