import { GoogleGenAI, Type, Modality } from "@google/genai";
import { ContentEmpireOutput, SalesFeedback, BoardOfDirectorsOutput } from "../types";

// Always create a new GoogleGenAI instance right before making an API call to ensure it uses the most up-to-date API key.
export const getGeminiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("Missing Gemini API Key");
  return new GoogleGenAI({ apiKey });
};

export async function transcribeAudio(base64Audio: string): Promise<string> {
  const ai = getGeminiClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          { inlineData: { mimeType: 'audio/webm', data: base64Audio } },
          { text: "Транскрибируй это аудио точно. Аудио может быть на русском или таджикском языке. Выведи только текст, без комментариев." }
        ]
      }
    ]
  });
  return response.text || "Ошибка транскрипции.";
}

