import { encode, decode, decodeAudioData } from '../utils/audioUtils';
import { Modality, LiveServerMessage } from '@google/genai';
import { SalesPersona, SalesFeedback } from '../types';

const PERSONAS: SalesPersona[] = [
  {
    id: 'skeptic',
    name: 'Скептик',
    description: 'Фокус на цене.',
    icon: 'UserX',
    instruction: 'Ты — скептичный клиент. "Дорого" — твой аргумент. Короткие ответы.'
