const SalesDojo: React.FC = () => {
  const [selectedPersona, setSelectedPersona] = useState<SalesPersona | null>(null);
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [feedback, setFeedback] = useState<SalesFeedback | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [transcript, setTranscript] = useState<string>("");

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const startTraining = async (persona: SalesPersona) => {
    setFeedback(null);
    setTranscript("");
    setIsConnecting(true);
    setSelectedPersona(persona);

    try {
      const ai = getGeminiClient();
      streamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true });
      audioContextRef.current = new AudioContext({ sampleRate: 16000 });
      outputAudioContextRef.current = new AudioContext({ sampleRate: 24000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsActive(true);
            setIsConnecting(false);
            const source = audioContextRef.current!.createMediaStreamSource(streamRef.current!);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
          },
          onmessage: async (m: LiveServerMessage) => {
            const audio = m.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audio) {
              const ctx = outputAudioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audio), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
            }
            if (m.serverContent?.outputTranscription) setTranscript(p => p + "\nКлиент: " + m.serverContent?.outputTranscription?.text);
            if (m.serverContent?.inputTranscription) setTranscript(p => p + "\nПродавец: " + m.serverContent?.inputTranscription?.text);
          },
          onerror: (e) => console.error(e),
          onclose: () => setIsActive(false),
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: persona.instruction,
          outputAudioTranscription: {},
          inputAudioTranscription: {},
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      setIsConnecting(false);
    }
  };

  const stopTraining = async () => {
    if (sessionRef.current) sessionRef.current.close();
    if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    setIsActive(false);
    if (transcript.length > 20) {
      setIsAnalyzing(true);
      try {
        const report = await generateSalesFeedback(transcript);
        setFeedback(report);
      } catch (err) {
      } finally {
        setIsAnalyzing(false);
      }
    }
  };

  return (
    <div className="px-4 py-8 animate-in fade-in duration-500">
      {!isActive && !feedback && !isAnalyzing && (
        <div className="space-y-8">
          <div className="text-center">
            <h1 className="text-4xl font-black tracking-tight">SALES <span className="gradient-text">DOJO</span></h1>
            <p className="text-xs text-zinc-500 font-bold uppercase tracking-widest mt-2">Выбери спарринг-партнера</p>
          </div>
          <div className="grid grid-cols-1 gap-4">
            {PERSONAS.map(p => (
              <button key={p.id} onClick={() => startTraining(p)} className="glass-card p-6 rounded-2xl text-left flex items-center gap-4 active:scale-95 transition-all">
                <div className="w-12 h-12 rounded-xl bg-amber-500/10 flex items-center justify-center text-amber-500">
                   {p.id === 'skeptic' ? <UserX size={24}/> : p.id === 'exec' ? <Award size={24}/> : <ShieldCheck size={24}/>}
                </div>
                <div>
                  <h3 className="font-bold text-white uppercase tracking-tight">{p.name}</h3>
                  <p className="text-[10px] text-zinc-500 uppercase font-bold tracking-tight">{p.description}</p>
                </div>
                <ChevronRight size={16} className="ml-auto text-zinc-700" />
              </button>
            ))}
          </div>
        </div>
      )}

      {isActive && (
        <div className="glass-card rounded-3xl p-8 text-center space-y-8 border-amber-500/30">
          <div className="relative w-20 h-20 mx-auto">
            <div className="absolute inset-0 bg-amber-500/20 rounded-full animate-ping"></div>
            <div className="relative w-full h-full bg-amber-500 rounded-full flex items-center justify-center text-zinc-900 shadow-xl shadow-amber-500/20">
              <Mic size={32} />
            </div>
          </div>
          <div className="space-y-1">
            <p className="text-[10px] font-black uppercase tracking-widest text-zinc-500">Бой с:</p>
            <h2 className="text-2xl font-black text-white uppercase tracking-tight">{selectedPersona?.name}</h2>
          </div>
          <button onClick={stopTraining} className="w-full py-4 bg-red-500 text-white rounded-2xl font-black uppercase tracking-widest text-sm shadow-xl shadow-red-500/10">
            Завершить раунд
          </button>
        </div>
      )}

      {isAnalyzing && (
        <div className="py-20 text-center space-y-6">
          <Loader2 size={40} className="text-amber-500 animate-spin mx-auto" />
          <p className="text-xs font-bold uppercase tracking-widest text-zinc-500">Тренер изучает запись...</p>
        </div>
      )}

      {feedback && (
        <div className="space-y-6">
          <div className="flex justify-between items-end">
            <h2 className="text-2xl font-black uppercase tracking-tight">Отчет боя</h2>
            <div className="text-3xl font-black text-amber-500">{feedback.score}<span className="text-sm text-zinc-600">/5</span></div>
          </div>
          <div className="glass-card p-6 rounded-2xl bg-amber-500/5">
            <p className="text-xs font-bold text-amber-500 uppercase tracking-widest mb-2">Совет тренера:</p>
            <p className="text-sm text-zinc-200 leading-relaxed italic">"{feedback.tips}"</p>
          </div>
          <button onClick={() => { setFeedback(null); setSelectedPersona(null); }} className="w-full py-4 bg-white/5 border border-white/10 rounded-2xl text-xs font-black uppercase tracking-widest">
            Начать заново
          </button>
        </div>
      )}
    </div>
  );
};

