    description: 'Прячется за спиной других.',
    icon: 'Users2',
    instruction: 'Ты — клиент, который не принимает решение сам. "Мне нужно посоветоваться с женой/директором/юристом". Продавец должен убедить тебя, что решение нужно принимать тебе, или договориться о встрече с тем, кто решает.'
  },
  {
    id: 'expert',
    name: 'Технарь',
    objectionType: 'ДЕТАЛИ',
    description: 'Ищет подвох в мелочах.',
    icon: 'ShieldCheck',
    instruction: 'Ты — эксперт, который знает тему лучше продавца. Ты задаешь каверзные вопросы о процессах и гарантиях. Если продавец плавает в матчасти — ты его "разносишь". Закрывай сделку только если он докажет свою экспертность.'
  },
  {
    id: 'tyrant',
    name: 'Диктатор',
    objectionType: 'АВТОРИТЕТ',
    description: 'Грубый, проверяет на прочность.',
    icon: 'BadgeAlert',
    instruction: 'Ты — альфа-клиент. Ты перебиваешь, ставишь под сомнение опыт продавца. "Кто вы такие? Почему я должен вам верить?". Продавец должен удержать позицию, не лебезить и закрыть тебя через статус и результаты.'
  }
];

const SalesDojo: React.FC = () => {
  const [selectedPersona, setSelectedPersona] = useState<SalesPersona | null>(null);
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [feedback, setFeedback] = useState<SalesFeedback | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [transcript, setTranscript] = useState<string>("");

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const startTraining = async (persona: SalesPersona) => {
    setFeedback(null);
    setTranscript("");
    setIsConnecting(true);
    setSelectedPersona(persona);

    try {
      const ai = getGeminiClient();
      streamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true });
      audioContextRef.current = new AudioContext({ sampleRate: 16000 });
      outputAudioContextRef.current = new AudioContext({ sampleRate: 24000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsActive(true);
            setIsConnecting(false);
            const source = audioContextRef.current!.createMediaStreamSource(streamRef.current!);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              sessionPromise.then(s => s.sendRealtimeInput({ media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' } }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
          },
          onmessage: async (m: LiveServerMessage) => {
            const audio = m.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audio) {
              const ctx = outputAudioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audio), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }
            if (m.serverContent?.outputTranscription) setTranscript(p => p + "\nКлиент: " + m.serverContent?.outputTranscription?.text);
            if (m.serverContent?.inputTranscription) setTranscript(p => p + "\nПродавец: " + m.serverContent?.inputTranscription?.text);
          },
          onerror: (e) => console.error(e),
          onclose: () => setIsActive(false),
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: `ТЫ — ЖЕСТКИЙ ТРЕНЕР ПО ПРОДАЖАМ В РОЛИ КЛИЕНТА. Твоя цель — НЕ ДАТЬ СЕБЯ ЗАКРЫТЬ. 
          Инструкция для персонажа: ${persona.instruction}
          Если продавец использует слабые аргументы, перебивай его или сомневайся еще сильнее. 
          Если продавец круто отработал возражение, использовал технику "Согласие-Перехват" или "Изоляция", постепенно смягчайся. 
          Разговор должен закончиться либо "Сделкой", либо твоим уходом.`,
          outputAudioTranscription: {},
          inputAudioTranscription: {},
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      setIsConnecting(false);
    }
  };

  const stopTraining = async () => {
    if (sessionRef.current) sessionRef.current.close();
    if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    setIsActive(false);
    if (transcript.length > 20) {
      setIsAnalyzing(true);
      try {
        const report = await generateSalesFeedback(transcript);
        setFeedback(report);
      } catch (err) {
      } finally {
        setIsAnalyzing(false);
      }
    }
  };

  const renderIcon = (iconName: string) => {
    const props = { size: 24 };
    switch (iconName) {
      case 'Coins': return <Coins {...props} />;
      case 'Clock': return <Clock {...props} />;
      case 'Users2': return <Users2 {...props} />;
      case 'ShieldCheck': return <ShieldCheck {...props} />;
      case 'BadgeAlert': return <BadgeAlert {...props} />;
      default: return <UserX {...props} />;
    }
  };

  return (
    <div className="px-4 py-8 animate-in fade-in duration-500">
      {!isActive && !feedback && !isAnalyzing && (
        <div className="space-y-8">
          <div className="text-center">
            <h1 className="text-4xl font-black tracking-tight">SALES <span className="gradient-text">DOJO</span></h1>
            <p className="text-xs text-zinc-500 font-bold uppercase tracking-widest mt-2">Выбери уровень сложности</p>
          </div>
          <div className="grid grid-cols-1 gap-4">
            {PERSONAS.map(p => (
              <button 
                key={p.id} 
                onClick={() => startTraining(p)} 
                className="glass-card p-5 rounded-2xl text-left flex items-center gap-4 active:scale-95 transition-all border-l-4 border-amber-500/30"
              >
                <div className="w-12 h-12 rounded-xl bg-amber-500/10 flex items-center justify-center text-amber-500">
                   {renderIcon(p.icon)}
                </div>
                <div className="flex-1">
                  <div className="flex items-center gap-2">
                    <h3 className="font-bold text-white uppercase tracking-tight text-sm">{p.name}</h3>
                    <span className="text-[8px] bg-red-500/20 text-red-500 px-1.5 py-0.5 rounded-full font-black uppercase tracking-widest">{p.objectionType}</span>
                  </div>
                  <p className="text-[10px] text-zinc-500 uppercase font-bold tracking-tight mt-1">{p.description}</p>
                </div>
                <ChevronRight size={16} className="text-zinc-700" />
              </button>
            ))}
          </div>
        </div>
      )}

      {isActive && (
        <div className="glass-card rounded-[40px] p-10 text-center space-y-10 border-amber-500/20 shadow-2xl shadow-amber-500/5">
          <div className="relative w-24 h-24 mx-auto">
            <div className="absolute inset-0 bg-amber-500/10 rounded-full animate-ping"></div>
            <div className="relative w-full h-full bg-gradient-to-br from-amber-400 to-amber-600 rounded-full flex items-center justify-center text-zinc-900 shadow-xl shadow-amber-500/20">
              <Mic size={40} />
            </div>
          </div>
          <div className="space-y-2">
            <span className="text-[10px] font-black uppercase tracking-[0.3em] text-amber-500">Идет Спарринг</span>
            <h2 className="text-3xl font-black text-white uppercase tracking-tight leading-none">{selectedPersona?.name}</h2>
            <p className="text-[10px] text-zinc-500 uppercase font-bold tracking-widest">Цель: Закрыть сделку</p>
          </div>
          <button 
            onClick={stopTraining} 
            className="w-full py-5 bg-red-500 hover:bg-red-600 text-white rounded-3xl font-black uppercase tracking-widest text-xs shadow-xl shadow-red-500/20 transition-all active:scale-95"
          >
            Сдаться / Завершить
          </button>
        </div>
      )}

      {isAnalyzing && (
        <div className="py-20 text-center space-y-8 animate-pulse">
          <div className="relative">
            <Loader2 size={48} className="text-amber-500 animate-spin mx-auto" />
            <BrainCircuit size={20} className="absolute inset-0 m-auto text-white" />
          </div>
          <div className="space-y-2">
            <p className="text-xs font-black uppercase tracking-[0.2em] text-zinc-500">ИИ-Тренер разбирает ошибки</p>
            <p className="text-[10px] text-zinc-700 uppercase font-bold">Считаем конверсию аргументов...</p>
          </div>
        </div>
      )}

      {feedback && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="flex justify-between items-end border-b border-white/5 pb-6">
            <div className="space-y-1">
              <span className="text-[10px] font-black uppercase tracking-widest text-zinc-500">Ваш результат</span>
              <h2 className="text-3xl font-black uppercase tracking-tight">Отчет боя</h2>
            </div>
            <div className="text-right">
              <div className="text-5xl font-black text-amber-500 leading-none">{feedback.score}</div>
              <div className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">из 5 баллов</div>
            </div>
          </div>

          <div className="grid grid-cols-1 gap-6">
            <div className="glass-card p-6 rounded-2xl border-l-4 border-green-500/30">
              <h4 className="text-[10px] font-black text-green-500 uppercase tracking-widest mb-4">Что сработало:</h4>
              <ul className="space-y-3">
                {feedback.strengths.map((s, i) => (
                  <li key={i} className="text-xs text-zinc-300 flex gap-2">
                    <span className="text-green-500 font-bold">•</span> {s}
                  </li>
                ))}
              </ul>
            </div>

            <div className="glass-card p-6 rounded-2xl border-l-4 border-red-500/30">
              <h4 className="text-[10px] font-black text-red-500 uppercase tracking-widest mb-4">Где слили:</h4>
              <ul className="space-y-3">
                {feedback.weaknesses.map((w, i) => (
                  <li key={i} className="text-xs text-zinc-300 flex gap-2">
                    <span className="text-red-500 font-bold">•</span> {w}
                  </li>
                ))}
              </ul>
            </div>

            <div className="glass-card p-6 rounded-3xl bg-amber-500/5 border border-amber-500/10">
              <div className="flex items-center gap-3 mb-3 text-amber-500">
                <Zap size={18} />
                <h4 className="text-[10px] font-black uppercase tracking-widest">Главный дожим:</h4>
              </div>
              <p className="text-sm text-zinc-200 leading-relaxed font-medium">"{feedback.tips}"</p>
            </div>
          </div>

          <button 
            onClick={() => { setFeedback(null); setSelectedPersona(null); }} 
            className="w-full py-5 bg-white/5 border border-white/10 hover:bg-white/10 rounded-3xl text-[10px] font-black uppercase tracking-widest transition-all"
          >
            Вернуться в зал ожидания
          </button>
        </div>
      )}
    </div>
  );
};

export default SalesDojo;
